// n8n Function node: normalize mixed multi-source JSON into a unified feed
const out = [];

function safeGet(obj, path, fallback = null) {
  try {
    return path.split('.').reduce((acc, k) => (acc && acc[k] !== undefined ? acc[k] : undefined), obj) ?? fallback;
  } catch (e) {
    return fallback;
  }
}

// Build blocks array from possible input shapes
let blocks = [];
if (!items || items.length === 0) {
  return []; // nothing to do
} else if (items.length === 1) {
  const j = items[0].json;
  if (Array.isArray(j)) {
    blocks = j; // already an array of blocks
  } else if (j && typeof j === 'object') {
    const tmp = [];
    if (Array.isArray(j.articles)) tmp.push({ articles: j.articles });
    if (Array.isArray(j.entities)) tmp.push({ entities: j.entities });
    if (j.data && (j.data.posts || Array.isArray(j.data))) tmp.push({ data: j.data });
    if (Array.isArray(j.tweets)) tmp.push({ tweets: j.tweets });
    blocks = tmp.length ? tmp : [j];
  } else {
    blocks = [j];
  }
} else {
  blocks = items.map(it => it.json);
}

// Process each block
for (const block of blocks) {
  if (!block || typeof block !== 'object') continue;

  // --- Google News (articles array) ---
  if (Array.isArray(block.articles)) {
    for (const article of block.articles) {
      out.push({
        source: safeGet(article, 'source.name', 'news'),
        type: 'google_news',
        title: article.title || null,
        description: article.description || article.content || null,
        url: article.url || article.link || null,
        publishedAt: article.publishedAt || null,
        raw: article
      });
    }
    continue;
  }

  // --- Crunchbase (entities) ---
  if (Array.isArray(block.entities)) {
    for (const ent of block.entities) {
      out.push({
        source: 'crunchbase',
        type: 'crunchbase',
        company: safeGet(ent, 'identifier.value', null),
        permalink: safeGet(ent, 'identifier.permalink', null),
        description: ent.short_description || null,
        facet_ids: ent.facet_ids || null,
        raw: ent
      });
    }
    continue;
  }

  // --- Product Hunt (data.posts.edges) ---
  const phEdges = safeGet(block, 'data.posts.edges', null) || safeGet(block, 'posts.edges', null);
  if (Array.isArray(phEdges)) {
    for (const edge of phEdges) {
      const node = edge.node || edge;
      out.push({
        source: 'product_hunt',
        type: 'product_hunt',
        name: safeGet(node, 'name', null),
        tagline: safeGet(node, 'tagline', null),
        votes: safeGet(node, 'votesCount', safeGet(node, 'votes', 0)),
        comments: safeGet(node, 'commentsCount', safeGet(node, 'comments', 0)),
        website: safeGet(node, 'website', null),
        createdAt: safeGet(node, 'createdAt', null),
        raw: node
      });
    }
    continue;
  }

  // --- Twitter/X (many shapes) ---
  const tweetCandidates = [];
  if (Array.isArray(block.data) && block.data.length && (block.data[0].text || block.data[0].full_text)) {
    tweetCandidates.push(...block.data);
  }
  if (Array.isArray(block.tweets)) tweetCandidates.push(...block.tweets);
  if (block.includes && Array.isArray(block.includes.tweets)) tweetCandidates.push(...block.includes.tweets);
  if (block.tweets && Array.isArray(block.tweets)) tweetCandidates.push(...block.tweets);
  if (Array.isArray(safeGet(block, 'data.tweets', null))) tweetCandidates.push(...block.data.tweets);

  // Deduplicate tweets by id
  const seen = new Set();
  const uniq = [];
  for (const t of tweetCandidates) {
    const tid = safeGet(t, 'id', null) || safeGet(t, 'tweet_id', null);
    if (!tid) continue;
    if (!seen.has(tid)) {
      seen.add(tid);
      uniq.push(t);
    }
  }

  if (uniq.length) {
    const userMap = {};
    if (block.includes && Array.isArray(block.includes.users)) {
      for (const u of block.includes.users) if (u.id) userMap[u.id] = u;
    }
    if (Array.isArray(block.users)) {
      for (const u of block.users) if (u.id) userMap[u.id] = u;
    }

    for (const tweet of uniq) {
      const authorId = safeGet(tweet, 'author_id', null) || safeGet(tweet, 'user.id', null);
      const user = authorId ? userMap[authorId] : null;
      out.push({
        source: 'twitter',
        type: 'twitter',
        author: tweet.username || safeGet(tweet, 'user.username', null) || (user ? user.username || user.name : null),
        text: tweet.text || tweet.full_text || null,
        createdAt: safeGet(tweet, 'created_at', safeGet(tweet, 'createdAt', null)),
        tweetId: safeGet(tweet, 'id', null),
        media: safeGet(tweet, 'attachments.media_keys', null) || safeGet(tweet, 'media_key', null),
        place: safeGet(tweet, 'place', null),
        raw: tweet
      });
    }
    continue;
  }

  // --- Generic fallback ---
  const guessTitle = safeGet(block, 'title', null) || safeGet(block, 'name', null);
  const guessDesc = safeGet(block, 'description', null) || safeGet(block, 'tagline', null);
  const guessUrl = safeGet(block, 'url', null) || safeGet(block, 'website', null);
  if (guessTitle || guessDesc || guessUrl) {
    out.push({
      source: safeGet(block, 'source.name', 'unknown'),
      type: 'generic',
      title: guessTitle,
      description: guessDesc,
      url: guessUrl,
      publishedAt: safeGet(block, 'publishedAt', safeGet(block, 'createdAt', null)),
      raw: block
    });
  } else {
    out.push({
      source: 'unknown',
      type: 'unmapped',
      raw: block
    });
  }
}

// Return items in n8n format
return out.map(r => ({ json: r }));

