// n8n Code Node (JavaScript)
return items.map(item => {
  let raw = item.json.output;

  // 1. Remove ```json ``` or ``` wrappers if present
  raw = raw.replace(/```json|```/g, "").trim();

  let parsed;
  try {
    // 2. Parse the JSON string safely
    parsed = JSON.parse(raw);
  } catch (e) {
    // If parsing fails, keep it null for debugging
    parsed = { error: "Invalid JSON", raw };
  }

  return {
    json: parsed
  };
});
